import{_ as a,a as t,b as d,c as n}from"./chunks/授权后复制刷新令牌.DFAJxpN4.js";import{_ as o,o as r,c as i,a2 as s}from"./chunks/framework.DnrXFDHb.js";const k=JSON.parse('{"title":"Adicionar canal Yandex","description":"","frontmatter":{},"headers":[],"relativePath":"pt-BR/upload/yandex.md","filePath":"pt-BR/upload/yandex.md","lastUpdated":1781962217000}'),l={name:"pt-BR/upload/yandex.md"};function p(c,e,h,m,u,b){return r(),i("div",null,[...e[0]||(e[0]=[s('<h1 id="adicionar-canal-yandex" tabindex="-1">Adicionar canal Yandex <a class="header-anchor" href="#adicionar-canal-yandex" aria-label="Permalink to &quot;Adicionar canal Yandex&quot;">​</a></h1><p>O canal Yandex usa o Yandex Disk como destino de armazenamento.</p><h2 id="o-que-preparar" tabindex="-1">O que preparar <a class="header-anchor" href="#o-que-preparar" aria-label="Permalink to &quot;O que preparar&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Item</th><th>Uso</th></tr></thead><tbody><tr><td>Conta Yandex</td><td>Autorizar Yandex Disk</td></tr><tr><td>Yandex OAuth App</td><td>Obter Client ID e Client Secret</td></tr><tr><td>Domínio ImgBed</td><td>Configurar callback OAuth</td></tr><tr><td>Yandex Disk</td><td>Salvar arquivos</td></tr></tbody></table><h2 id="criar-yandex-oauth-app" tabindex="-1">Criar Yandex OAuth App <a class="header-anchor" href="#criar-yandex-oauth-app" aria-label="Permalink to &quot;Criar Yandex OAuth App&quot;">​</a></h2><p>Abra:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://oauth.yandex.com/client/new</span></span></code></pre></div><p>Se pedir login, entre com a conta Yandex que será usada como armazenamento.</p><p>Crie um app e dê um nome reconhecível:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>imgbed-yandex</span></span></code></pre></div><p>Em callback URL, informe:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://seu-dominio/api/oauth/yandex/callback</span></span></code></pre></div><h2 id="permissoes" tabindex="-1">Permissões <a class="header-anchor" href="#permissoes" aria-label="Permalink to &quot;Permissões&quot;">​</a></h2><p>O ImgBed usa estas permissões de <code>Yandex.Disk REST API</code>:</p><table tabindex="0"><thead><tr><th>Permissão</th><th>Uso</th></tr></thead><tbody><tr><td><code>cloud_api:disk.app_folder</code></td><td>Salvar arquivos na pasta do app</td></tr><tr><td><code>cloud_api:disk.read</code></td><td>Ler arquivos e links de download</td></tr><tr><td><code>cloud_api:disk.write</code></td><td>Enviar, criar pastas e excluir</td></tr><tr><td><code>Access to information about Yandex.Disk</code></td><td>Ler capacidade e uso</td></tr></tbody></table><p>Permissões de nome ou e-mail em <code>Yandex ID API</code> são opcionais. As funções principais dependem das permissões do Disk.</p><p><img src="'+a+'" alt="Permissões Yandex Disk" loading="lazy"></p><h2 id="copiar-client-id-e-secret" tabindex="-1">Copiar Client ID e Secret <a class="header-anchor" href="#copiar-client-id-e-secret" aria-label="Permalink to &quot;Copiar Client ID e Secret&quot;">​</a></h2><p>Depois de criar o app, copie:</p><table tabindex="0"><thead><tr><th>Campo Yandex</th><th>Campo ImgBed</th></tr></thead><tbody><tr><td><code>Client ID</code></td><td><code>Client ID</code></td></tr><tr><td><code>Client Secret</code></td><td><code>Client Secret</code></td></tr></tbody></table><p><img src="'+t+'" alt="Client ID e Secret" loading="lazy"></p><h2 id="preencher-no-imgbed" tabindex="-1">Preencher no ImgBed <a class="header-anchor" href="#preencher-no-imgbed" aria-label="Permalink to &quot;Preencher no ImgBed&quot;">​</a></h2><p>Em Configurações de upload, escolha <code>Yandex</code>.</p><table tabindex="0"><thead><tr><th>Campo</th><th>Valor</th></tr></thead><tbody><tr><td>Nome do canal</td><td>Por exemplo <code>Yandex Main</code></td></tr><tr><td>Client ID</td><td>Client ID do app</td></tr><tr><td>Client Secret</td><td>Client Secret do app</td></tr><tr><td>Refresh Token</td><td>Deixe vazio no início</td></tr><tr><td>Diretório raiz</td><td>Opcional, normalmente <code>imgbed</code></td></tr></tbody></table><p><img src="'+d+'" alt="Configuração Yandex" loading="lazy"></p><h2 id="obter-refresh-token" tabindex="-1">Obter Refresh Token <a class="header-anchor" href="#obter-refresh-token" aria-label="Permalink to &quot;Obter Refresh Token&quot;">​</a></h2><ol><li>No ImgBed, clique em <code>Obter Token</code>.</li><li>Entre com a conta Yandex de destino.</li><li>Aceite as permissões.</li><li>Copie o <code>Refresh Token</code> exibido na página de callback.</li><li>Cole no ImgBed.</li></ol><p><img src="'+n+`" alt="Refresh Token" loading="lazy"></p><h2 id="fluxo-rapido" tabindex="-1">Fluxo rápido <a class="header-anchor" href="#fluxo-rapido" aria-label="Permalink to &quot;Fluxo rápido&quot;">​</a></h2><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Abrir Yandex OAuth Console</span></span>
<span class="line"><span>-&gt; Criar App</span></span>
<span class="line"><span>-&gt; Configurar https://seu-dominio/api/oauth/yandex/callback</span></span>
<span class="line"><span>-&gt; Confirmar permissões Disk</span></span>
<span class="line"><span>-&gt; Copiar Client ID / Client Secret</span></span>
<span class="line"><span>-&gt; Preencher no ImgBed</span></span>
<span class="line"><span>-&gt; Obter Token</span></span>
<span class="line"><span>-&gt; Colar Refresh Token e salvar</span></span></code></pre></div><h2 id="referencias" tabindex="-1">Referências <a class="header-anchor" href="#referencias" aria-label="Permalink to &quot;Referências&quot;">​</a></h2><ol><li>Registrar app Yandex: <a href="https://yandex.com/dev/id/doc/en/register-client" target="_blank" rel="noreferrer">https://yandex.com/dev/id/doc/en/register-client</a></li><li>Código de autorização por URL: <a href="https://yandex.com/dev/id/doc/en/codes/code-url" target="_blank" rel="noreferrer">https://yandex.com/dev/id/doc/en/codes/code-url</a></li><li>API de token OAuth: <a href="https://yandex.com/dev/id/doc/en/tokens/token" target="_blank" rel="noreferrer">https://yandex.com/dev/id/doc/en/tokens/token</a></li></ol>`,32)])])}const f=o(l,[["render",p]]);export{k as __pageData,f as default};
